"use client";

import { useId, useState, type ChangeEvent } from "react";

import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";

const maxLength = 200;
const initialValue = "";

const Textarea18 = () => {
  const [value, setValue] = useState(initialValue);
  const [characterCount, setCharacterCount] = useState(initialValue.length);

  const id = useId();

  const handleChange = (e: ChangeEvent<HTMLTextAreaElement>) => {
    if (e.target.value.length <= maxLength) {
      setValue(e.target.value);
      setCharacterCount(e.target.value.length);
    }
  };

  return (
    <div className="w-full max-w-sm space-y-2">
      <Label htmlFor={id}>Brief summary</Label>
      <Textarea
        id={id}
        placeholder="Write a short summary..."
        value={value}
        maxLength={maxLength}
        onChange={handleChange}
        className="focus-visible:ring-primary/20 focus-visible:border-primary/50 rounded-sm shadow-sm focus-visible:ring-2"
      />
      <p className="text-muted-foreground text-xs">
        <span className="tabular-nums">{maxLength - characterCount}</span>{" "}
        remaining
      </p>
    </div>
  );
};

export default Textarea18;
